-- ============================================================================
-- CourtZon V2 – Egypt Cities/Districts Polygons
-- Generated from geoBoundaries-EGY-ADM2
-- ============================================================================

-- Schema changes
ALTER TABLE cities ADD COLUMN IF NOT EXISTS type VARCHAR(50) NULL;
ALTER TABLE cities ADD COLUMN IF NOT EXISTS slug VARCHAR(200) NULL;
ALTER TABLE provinces ADD COLUMN IF NOT EXISTS slug VARCHAR(200) NULL;

-- Indexes
CREATE INDEX IF NOT EXISTS idx_city_name ON cities(name);
CREATE INDEX IF NOT EXISTS idx_city_slug ON cities(slug);
CREATE INDEX IF NOT EXISTS idx_province_name ON provinces(name);
CREATE INDEX IF NOT EXISTS idx_country_name ON countries(name);

